// Mapeo de valores del formulario → Azure DevOps API
const mapaResultados = {
  'Exitoso':     'Passed',
  'Fallido':     'Failed',
  'Bloqueado':   'Blocked',
  'No aplicable': 'NotApplicable',
  'Paused': 'Paused'
};

// Obtener la fecha actual en formato ISO con milisegundos
const fechaActual = new Date();
const fechaFormateada = fechaActual.toISOString().slice(0, -1); // Remueve la 'Z' final
// Formato: 2026-02-14T20:30:57.123

// Obtener el valor del formulario
const resultadoFormulario = $('Recibir datos de ejecución').first().json.body.resultado;

// Convertir al valor que necesita Azure DevOps
const outcomeAzure = mapaResultados[resultadoFormulario];

// Validar que el valor existe en el mapa
if (!outcomeAzure) {
  throw new Error(`Resultado no reconocido: "${resultadoFormulario}". Valores válidos: ${Object.keys(mapaResultados).join(', ')}`);
}

// Determinar acción con los tags
let accionTag = 'ninguna';
let tagToAdd = null;
let debeQuitarTag = false;

if (resultadoFormulario === 'Paused') {
  // Si es Paused, agregar el tag
  accionTag = 'agregar';
  tagToAdd = 'PTMO';
  debeQuitarTag = false;
} else {
  // Si es cualquier otro estado, quitar el tag
  accionTag = 'quitar';
  tagToAdd = null;
  debeQuitarTag = true;
}

console.log(`Acción tag: ${accionTag}, Tag: ${tagToAdd}, Debe quitar: ${debeQuitarTag}`);


// Pasar todos los datos 
return [{
  json: {
    ...$json,                      // Mantiene todos los campos del formulario
    outcomeAzure: outcomeAzure,    // Agrega el outcome convertido
    completedDate: fechaFormateada, // Agrega la fecha actual
    accionTag: accionTag,
    tagToAdd: tagToAdd,
    debeQuitarTag: debeQuitarTag
  }
}];

// Recuperar el binario del nodo trigger (donde está el archivo)
const binaryData = $('Recibir datos de ejecución').item.binary;

// Verificar que existe el archivo
if (!binaryData || !binaryData.documento) {
  throw new Error('No se encontró el archivo de evidencia en el formulario');
}

// Retornar el item actual pero con el binario adjunto
return [{
  json: $json,         // Mantiene los datos JSON del nodo anterior
  binary: {
    documento: binaryData.documento  // Inyecta el binario con el nombre 'documento'
  }
}];

