// 1. Inicializamos variables básicas

let acciones = [];
let statusFinal = "exito"; 
let mensajeFinal = "Se completo el proceso correctamente";

// 2. Función segura para obtener datos

const obtenerDatosSeguro = (nombre) => {
    try {
        const resultado = $(nombre).first();
        return resultado ? resultado.json : null;
    } catch (e) {
        return null;
    }
};

// 3. Extraemos los valores de entrada (Webhook) usando la ruta exacta

const inputData = obtenerDatosSeguro('Recibir datos de ejecución')?.body || {};

const idBug = inputData.bugExistente || "N/A";
const idImp = inputData.impedimento || "N/A";
const idTestCase = inputData.testcase || "N/A";
const valorResultado = inputData.resultado || "procesado";

const namebugnuevo = inputData.bugTitulo || "N/A";


// <--- Aquí extraemos tu variable
const idBugNuevo = obtenerDatosSeguro('Crear Bug') || {};
const idbugNuevo2 =  idBugNuevo.id || "N/A";

const nameBug = obtenerDatosSeguro('Obtener Bug')?.fields || {};
const nameBugexistente = nameBug['System.Title'];

const idImpRel = obtenerDatosSeguro('Obtener impedimento')?.fields || {};
const idImpRel2 = idImpRel['System.Title'];

// --- 4. VALIDACIÓN DE ERRORES (Prioridad) ---

if (obtenerDatosSeguro('Validacion existencia impedimento')?.error?.code === 'ERR_BAD_REQUEST') {
    return { 
        tipo: "error", 
        mensaje: `El impedimento ${idImp} no existe. No se registró la ejecución.`, 
        acciones: "" 
    };
}

if (obtenerDatosSeguro('Validacion existencia TestCase')?.error?.code === 'ERR_BAD_REQUEST') {
    return { 
        tipo: "error", 
        mensaje: `El TestCase ${idTestCase} no existe. No se registró la ejecución.`, 
        acciones: "" 
    };
}

if (obtenerDatosSeguro('Obtener Bug')?.error?.code === 'ERR_BAD_REQUEST') {
    return { 
        tipo: "error", 
        mensaje: `El bug ${idBug} no existe. No se registró la ejecución.`, 
        acciones: "" 
    };
}


if (obtenerDatosSeguro('SubEstados Cerrados')) {
    return { 
        tipo: "error", 
        mensaje: `El ID ${idBug} no es un Bug o este se encuentra cerrado. No se registró la ejecución. `, 
        acciones: "" 
    };
}

if (obtenerDatosSeguro('Validación Impedimento')) {
  return { 
        tipo: "error", 
        mensaje: `El ID ${idImp} no es un Impedimento o este se encuentra cerrado. No se registró la ejecución.`, 
        acciones: "" 
    };
}

if (obtenerDatosSeguro('Validación TestCase')) {
  return { 
        tipo: "error", 
        mensaje: `El ID ${idTestCase} no es un Test Case. No se registró la ejecución. `, 
        acciones: "" 
    };
}



// --- 5. VALIDACIÓN DE ACCIONES (Acumulativo) ---

if (obtenerDatosSeguro('Crear Bug')) {
    acciones.push(`Se creó el bug ${idbugNuevo2}: ${namebugnuevo} en el sistema.`);
}

if (obtenerDatosSeguro('Relacionar Impedimento')) {
    acciones.push(`Se relacionó el impedimento ${idImp}: ${idImpRel2}.`);
    acciones.push(`Se registró el resultado de la ejecución (${valorResultado}).`);
}

if (obtenerDatosSeguro('SubEstado Reapertura')) {
    acciones.push(`Se relacionó el bug ${idBug}: ${nameBugexistente}.`);
}

if (obtenerDatosSeguro('Reapertura Bug')) {
    acciones.push(`Se reaperturó el bug ${idBug}.`);
}

// Acción: Registro ejecución (Usa la variable dinámica valorResultado)

if (obtenerDatosSeguro('flujo exitoso bloq paused')) {
    acciones.push(`Se registró el resultado de la ejecución (${valorResultado}).`);
}

// Acción: Asociar Documento (También usa valorResultado)

if (obtenerDatosSeguro('Asociar Documento'))  {
    acciones.push("Se asoció la evidencia.");
    acciones.push(`Se registró el resultado de la ejecución (${valorResultado}).`);

}

if (obtenerDatosSeguro('Comentario de registro') || obtenerDatosSeguro('Guardar comentario')) {
    acciones.push("Se registró el comentario.");
    acciones.push(`Se registró el resultado de la ejecución (${valorResultado}).`);
}

// --- 6. LIMPIEZA Y SALIDA FINAL ---

// El Set asegura que si se registró el resultado por dos nodos distintos, solo aparezca una vez

const accionesUnicas = [...new Set(acciones)];

if (statusFinal === "exito" && accionesUnicas.length === 0) {
    mensajeFinal = "No se realizaron cambios en los sistemas.";
}

return {

    tipo: statusFinal,
    mensaje: mensajeFinal,
    acciones: accionesUnicas.join('|') 

};

// Recuperar el binario del nodo trigger (donde está el archivo)
const binaryData = $('Recibir datos de ejecución').item.binary;

// Verificar que existe el archivo
if (!binaryData || !binaryData.documento) {
  throw new Error('No se encontró el archivo de evidencia en el formulario');
}

// Retornar el item actual pero con el binario adjunto
return [{
  json: $json,         // Mantiene los datos JSON del nodo anterior
  binary: {
    documento: binaryData.documento  // Inyecta el binario con el nombre 'documento'
  }
}];
